class ASTNode:
    """Node for Abstract Syntax Tree"""
    def __init__(self, node_type, value=None, left=None, right=None):
        self.type = node_type
        self.value = value
        self.left = left
        self.right = right

    def __str__(self, level=0):
        ret = "  " * level + f"{self.type}: {self.value}\n"
        if self.left:
            ret += self.left.__str__(level + 1)
        if self.right:
            ret += self.right.__str__(level + 1)
        return ret

class RecursiveDescentParser:
    """Parser for arithmetic expressions using recursive descent"""

    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def current_token(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return (None, None)

    def consume(self, expected_type=None):
        token = self.current_token()
        if expected_type and token[0] != expected_type:
            raise ValueError(f"Expected {expected_type}, got {token[0]}")
        self.pos += 1
        return token

    def parse(self):
        """Start parsing - entry point"""
        return self.parse_expression()

    def parse_expression(self):
        """Parse addition/subtraction: term (('+' | '-') term)*"""
        left = self.parse_term()

        while self.current_token()[1] in ('+', '-'):
            op = self.consume()[1]
            right = self.parse_term()
            left = ASTNode('BINARY_OP', op, left, right)

        return left

    def parse_term(self):
        """Parse multiplication/division: factor (('*' | '/') factor)*"""
        left = self.parse_factor()

        while self.current_token()[1] in ('*', '/'):
            op = self.consume()[1]
            right = self.parse_factor()
            left = ASTNode('BINARY_OP', op, left, right)

        return left

    def parse_factor(self):
        """Parse parentheses or number: '(' expression ')' | NUMBER"""
        token = self.current_token()

        if token[1] == '(':
            self.consume()
            node = self.parse_expression()
            self.consume('OPERATOR')  # consume ')'
            return node
        else:
            return self.parse_number()

    def parse_number(self):
        """Parse numeric literal"""
        token = self.consume()
        return ASTNode('NUMBER', token[1])

# Example usage
tokenizer = RecursiveDescentParser([])
# Using previous tokenizer to get tokens
from simpleTokenizer import Tokenizer
t = Tokenizer()
tokens = t.tokenize("3 + 4 * 2 - (5 / 1)")
# Filter only OPERATOR and NUMBER tokens for arithmetic
arith_tokens = [(t[0], t[1]) for t in tokens if t[0] in ('NUMBER', 'OPERATOR')]

parser = RecursiveDescentParser(arith_tokens)
ast = parser.parse()
print("Abstract Syntax Tree:")
print(ast)

import re

class DependencyParser:
    """Simple rule-based dependency parser for NLP"""

    def __init__(self):
        # Simple POS tag patterns
        self.pos_rules = {
            'NN': r'\b(the|a|an)\s+([a-z]+)\b',
            'VB': r'\b(is|are|was|were|eat|eats|run|runs|see|sees|love|loves)\b',
            'JJ': r'\b(quick|brown|lazy|happy|smart|intelligent|artificial)\b',
            'PREP': r'\b(in|on|at|with|for|from|to)\b',
        }

    def tokenize_sentence(self, sentence):
        """Split sentence into words"""
        return re.findall(r'\b\w+\b', sentence.lower())

    def simple_pos_tagging(self, words):
        """Assign simple POS tags based on word lists"""
        verbs = {'is', 'are', 'was', 'were', 'eat', 'eats', 'run', 'runs', 'see', 'sees', 'love', 'loves', 'learns', 'processes'}
        adjectives = {'quick', 'brown', 'lazy', 'happy', 'smart', 'intelligent', 'artificial', 'neural', 'deep'}
        prepositions = {'in', 'on', 'at', 'with', 'for', 'from', 'to', 'by'}

        tagged = []
        for word in words:
            if word in verbs:
                tagged.append((word, 'VB'))
            elif word in adjectives:
                tagged.append((word, 'JJ'))
            elif word in prepositions:
                tagged.append((word, 'PREP'))
            else:
                tagged.append((word, 'NN'))
        return tagged

    def parse_dependencies(self, tagged_sentence):
        """Build dependency relationships"""
        dependencies = []
        root = None

        for i, (word, pos) in enumerate(tagged_sentence):
            if pos == 'VB' and root is None:
                root = (word, i)

        if root:
            dependencies.append((root[0], 'ROOT', -1))

        for i, (word, pos) in enumerate(tagged_sentence):
            if i == root[1]:
                continue

            if pos == 'JJ':
                # Adjective modifies next noun
                dep_type = 'amod'
                head = root[0] if root else word
            elif pos == 'PREP':
                dep_type = 'prep'
                head = root[0] if root else word
            else:
                dep_type = 'nsubj' if i < root[1] else 'dobj' if root else 'root'
                head = root[0] if root else word

            dependencies.append((word, dep_type, head))

        return dependencies

    def parse(self, sentence):
        """Full parsing pipeline"""
        words = self.tokenize_sentence(sentence)
        tagged = self.simple_pos_tagging(words)
        dependencies = self.parse_dependencies(tagged)
        return {
            'words': words,
            'tagged': tagged,
            'dependencies': dependencies
        }

# Example usage
parser = DependencyParser()

sentences = [
    "The AI system processes neural data",
    "Artificial intelligence learns quickly",
    "The smart model understands complex patterns"
]

for sentence in sentences:
    print(f"\nSentence: {sentence}")
    result = parser.parse(sentence)
    print(f"Tagged: {result['tagged']}")
    print("Dependencies:")
    for word, dep_type, head in result['dependencies']:
        if head == -1:
            print(f"  {word} -> ROOT")
        else:
            print(f"  {word} -> {dep_type} -> {head}")
